    int vr = query(a, b, k*2+2, m, r);

    return op_(vl, vr);

  }

  int query(int a, int b){ return query(a, b, 0, 0, NN); }

};





using seg2k = seg_tree<int, 2048>;

seg2k::OP min_op = [](int x, int y){ return std::min(x, y); };

seg2k::OP max_op = [](int x, int y){ return std::max(x, y); };



