    for(int x = N; x > y; --x) { // play for Y

      int res = std::abs(a[N+1] - a[x]);

      res = std::min(res, xy[x].query(N-x));

      yx[y].add(N+1-x, res);

    }

    for(int x = y-1; x >= 0; --x) { // play for X

      int res = std::abs(a[N+1] - a[y]);

      res = std::max(res, yx[y].query(N-y));

      if(y==1 && x==0) fin(res);

      xy[x].add(N+1-y, res);

    }

